26.         {
27.             try
28.             {
29.                 var userName = "System"; // No authentication, use System as default user
30.                 notificationService.SendNotification(entityType, entityId, entityDisplayName, operation, userName);
31.             }
32.             catch (Exception ex)
33.             {
34.                 // Log the error but don't break the main operation
35.                 System.Diagnostics.Debug.WriteLine($"Failed to send notification: {ex.Message}");
